mapper.select:
SELECT rm.id, rm.dormitory_id, d.name AS dormitory_name, rm.name, rm.capacity, rm.version, rm.created_at, rm.updated_at, COUNT(rh.id) AS current_occupancy FROM rooms rm LEFT JOIN dormitories d ON d.id = rm.dormitory_id AND d.deleted_at IS NULL LEFT JOIN residence_histories rh ON rh.room_id = rm.id AND rh.check_in_date <= CURDATE() AND (rh.check_out_date IS NULL OR rh.check_out_date >= CURDATE()) AND rh.deleted_at IS NULL WHERE rm.deleted_at IS NULL
AND rm.dormitory_id = #{dormitoryId}
GROUP BY rm.id, rm.dormitory_id, d.name, rm.name, rm.capacity, rm.version, rm.created_at, rm.updated_at ORDER BY rm.dormitory_id ASC, rm.name ASC LIMIT #{offset}, #{pageSize}

SELECT rm.id AS room_id, rm.name AS room_name, dom.id AS dormitory_id, dom.name AS dormitory_name FROM rooms rm JOIN dormitories dom ON dom.id = rm.dormitory_id AND dom.deleted_at IS NULL LEFT JOIN regions reg ON reg.id = dom.region_id AND reg.deleted_at IS NULL WHERE rm.deleted_at IS NULL
AND reg.id = #{regionId}
ORDER BY dom.id ASC, rm.id ASC
